const crypto = require('crypto');

const input = $input.first().json;
const videoUrl = input.video_url || '';
const musicFileId = input.music_file_id || '';
const caption = input.caption || '';
const title = input.title || '';

if (!videoUrl) {
  throw new Error('video_url is required');
}

const uuid = crypto.randomUUID();
const rawPath = `/files/output/${uuid}_raw.mp4`;
const finalPath = `/files/output/${uuid}_final.mp4`;
const audioPath = musicFileId ? `/files/music/${musicFileId}.mp3` : '';

return [{
  json: {
    uuid,
    raw_path: rawPath,
    audio_path: audioPath,
    final_path: finalPath,
    video_url: videoUrl,
    music_file_id: musicFileId,
    caption,
    title,
    has_music: !!musicFileId,
    has_text: !!(caption || title)
  }
}];

const fs = require('fs');
const prep = $('Prepare Paths').first().json;
const rawPath = prep.raw_path;
const videoUrl = prep.video_url;

const response = await fetch(videoUrl);
if (!response.ok) throw new Error(`Failed to download video: ${response.status} ${response.statusText}`);

const buffer = Buffer.from(await response.arrayBuffer());
fs.mkdirSync(require('path').dirname(rawPath), { recursive: true });
fs.writeFileSync(rawPath, buffer);

return [{ json: { ...prep, downloaded: true } }];

// Re-read fields from the Prepare Paths node output (available via $('Prepare Paths').first().json)
const prep = $('Prepare Paths').first().json;
const uuid = prep.uuid;
const rawPath = prep.raw_path;
const finalPath = prep.final_path;
const audioPath = prep.audio_path;
const hasMusic = prep.has_music;
const hasText = prep.has_text;
const title = prep.title || '';
const caption = prep.caption || '';

// Escape single quotes in text for ffmpeg drawtext
const escapeDrawtext = (s) => s.replace(/'/g, "\\\\'").replace(/:/g, '\\\\:').replace(/"/g, '\\\\"');
const safeTitle = escapeDrawtext(title);
const safeCaption = escapeDrawtext(caption);

let command;

if (hasMusic && hasText) {
  const vf = [
    `drawtext=fontfile=/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf:text='${safeTitle}':fontcolor=white:fontsize=48:x=(w-text_w)/2:y=60:enable='lt(t,3)'`,
    `drawtext=fontfile=/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf:text='${safeCaption}':fontcolor=white:fontsize=28:x=(w-text_w)/2:y=h-80`
  ].join(',');
  command = `ffmpeg -y -i ${rawPath} -i ${audioPath} -map 0:v -map 1:a -vf "${vf}" -codec:v libx264 -shortest ${finalPath}`;
} else if (hasMusic) {
  command = `ffmpeg -y -i ${rawPath} -i ${audioPath} -map 0:v -map 1:a -c:v copy -shortest ${finalPath}`;
} else if (hasText) {
  const vf = [
    `drawtext=fontfile=/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf:text='${safeTitle}':fontcolor=white:fontsize=48:x=(w-text_w)/2:y=60:enable='lt(t,3)'`,
    `drawtext=fontfile=/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf:text='${safeCaption}':fontcolor=white:fontsize=28:x=(w-text_w)/2:y=h-80`
  ].join(',');
  command = `ffmpeg -y -i ${rawPath} -vf "${vf}" -codec:a copy ${finalPath}`;
} else {
  command = `cp ${rawPath} ${finalPath}`;
}

return [{ json: { uuid, final_path: finalPath, command } }];

const { execSync } = require('child_process');
const prep = $('Build FFmpeg Command').first().json;
const command = prep.command;

try {
  execSync(command, { encoding: 'utf8', timeout: 300000 });
} catch (e) {
  throw new Error(`FFmpeg failed: ${e.message}\nCommand: ${command}`);
}

return [{ json: { uuid: prep.uuid, final_path: prep.final_path, command } }];
